# 输入获取
src = input()
tar = input()


def indexOf(levels):
    # 滑动匹配levels.length长度的子串
    for i in range(len(src) - len(levels) + 1):
        isFind = True

        for j in range(len(levels)):
            if src[i + j] not in levels[j]:
                isFind = False
                break

        if isFind:
            return i

    return -1


# 核心代码
def getResult():
    # 将tar字符串转化为levels多层结构,转化逻辑为&#xff1a;tar字符串中,每个[]包含的所有字符作为一层,未被[]包含的单个字符作为一层
    levels = []

    # level用于记录[]中的字符
    level = set()
    isOpen = False

    for c in tar:
        if c == '[':
            isOpen = True
        elif c == ']':
            isOpen = False
            levels.append(level)
            level = set()
        else:
            if isOpen:
                level.add(c)
            else:
                levels.append({c})

    return indexOf(levels)


# 算法调用
print(getResult())
